package app.locallexis.data.db

import org.junit.Assert.assertTrue
import org.junit.Test
import java.io.File

/**
 * Schema-export bootstrap test.
 *
 * Asserts the v1 schema JSON is generated by KSP into `schemas/`. Once v2
 * arrives, add a second test using MigrationTestHelper.runMigrationsAndValidate
 * to verify v1 -> v2 migrations against the exported schemas. JVM-only —
 * Room 2.6 MigrationTestHelper needs instrumentation, which we'll wire as
 * an androidTest source set when migrations actually exist.
 */
class MigrationTest {

    @Test
    fun schemaV1IsExported() {
        val schema = File(SCHEMA_DIR, "1.json")
        assertTrue(
            "v1 schema missing at ${schema.absolutePath}. " +
                "Check ksp { arg(\"room.schemaLocation\", ...) } in build.gradle.kts.",
            schema.exists(),
        )
        val text = schema.readText()
        // Spot-check the entity tables made it into the export.
        for (table in listOf("transcripts", "segments", "segments_fts", "speakers", "devices", "sync_state")) {
            assertTrue(
                "schema missing table '$table'",
                text.contains("\"tableName\": \"$table\""),
            )
        }
    }

    companion object {
        private val SCHEMA_DIR = File("schemas/app.locallexis.data.db.LocalLexisDatabase")
    }
}
